import React from "react";

export default function Topbar() {
  return (
    <header className="topbar">
      <div style={{ display: "flex", alignItems: "center", gap: "14px" }}>
        <div style={{ fontSize: "22px", fontWeight: 700, color: "#fff", letterSpacing: "-0.5px" }}>
          Shop<span style={{ color: "#ffe500" }}>Kart</span>
        </div>
        <div className="topbar-tagline" style={{ fontSize: "12px", color: "rgba(255,255,255,.85)", fontStyle: "italic" }}>
          India's #1 Online Marketplace
        </div>
      </div>
      <div style={{ fontSize: "12px", color: "rgba(255,255,255,.7)", flexShrink: 0 }}>
        Already a member?{" "}
        <a href="#login" style={{ color: "#ffe500", fontWeight: 600 }}>Log in</a>
      </div>
    </header>
  );
}
